-- Delete old tables
SET FOREIGN_KEY_CHECKS = 0;
DROP TABLE IF EXISTS `licee`;
DROP TABLE IF EXISTS `specializari`;
DROP TABLE IF EXISTS `medii_admitere`;
SET FOREIGN_KEY_CHECKS = 1;

-- Create tables
CREATE TABLE licee (
  id_liceu VARCHAR(20) PRIMARY KEY,
  nume VARCHAR(200),
  tip VARCHAR(100),
  sector INT CHECK(sector >= 1 AND sector <= 6),
  adresa VARCHAR(255)
);

CREATE TABLE specializari (
  id_specializare INT AUTO_INCREMENT PRIMARY KEY,
  id_liceu VARCHAR(20),
  profil VARCHAR(150),
  specializare VARCHAR(150),
  limba VARCHAR(100),
  bilingv VARCHAR(100),
  cod_specializare INT UNIQUE,
  medie_actuala DECIMAL(4,2),
  FOREIGN KEY (id_liceu) REFERENCES licee(id_liceu)
);

CREATE TABLE medii_admitere (
  cod_specializare INT,
  an INT,
  medie DECIMAL(4,2),
  FOREIGN KEY (cod_specializare) REFERENCES specializari(cod_specializare)
);

